정탐코드의 예
1: public static int[] insertRandom(int[] Cnt, int i ,int scope) {
2: int ran = (int) (Math.random() * scope) - 1;
3: if (checkDigit(ran,Cnt)) {
4: Cnt[i] = ran;
5: } else {
6: insertRandom(Cnt,i,scope);
7: }
8: return Cnt;
9: }
